// The Agent node always wraps its result in { output: "..." }.
// The LLM puts a JSON string inside that field.
// This node unwraps it and ensures redirect params are properly URL-encoded.

const raw = $input.first().json.output ?? '';

let parsed;
try {
  // The LLM may return a plain JSON string or wrap it in markdown code fences
  const clean = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  parsed = JSON.parse(clean);
} catch (_) {
  // If parsing fails, treat the whole string as the output text
  parsed = { output: raw, redirect: '/' };
}

// Normalize and encode the redirect URL
function normalizeRedirect(url) {
  if (!url || url === '/') return '/';

  // Split path from query string
  const qIdx = url.indexOf('?');
  if (qIdx === -1) return url;

  const path = url.slice(0, qIdx);
  const qs = url.slice(qIdx + 1);

  // Parse and re-encode each param value
  // We use a manual split to preserve param names and handle already-encoded values
  const params = qs.split('&').map(pair => {
    const eqIdx = pair.indexOf('=');
    if (eqIdx === -1) return pair;
    const key = pair.slice(0, eqIdx);
    const rawValue = pair.slice(eqIdx + 1);
    // Decode first (in case LLM already partially encoded), then re-encode cleanly
    let decoded;
    try { decoded = decodeURIComponent(rawValue); } catch (_) { decoded = rawValue; }
    // encodeURIComponent encodes spaces as %20, keeps alphanumerics and - _ . ! ~ * ' ( )
    // For URL path params we want to preserve hyphens and tildes as-is (they're valid)
    const encoded = encodeURIComponent(decoded);
    return `${key}=${encoded}`;
  });

  return `${path}?${params.join('&')}`;
}

return [{
  json: {
    output: parsed.output ?? raw,
    redirect: normalizeRedirect(parsed.redirect ?? '/')
  }
}];
